-- MedSync master product catalog — Vetcove order history 2023–2026
-- 1180 unique products

-- Step 1: add unique constraint on name (safe — skips if already exists)
DO $$ BEGIN
  ALTER TABLE public.products ADD CONSTRAINT products_name_unique UNIQUE (name);
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Step 2: add purchase_unit column (Vetcove ordering/receiving unit)
ALTER TABLE public.products ADD COLUMN IF NOT EXISTS purchase_unit TEXT;

-- Step 3: upsert all products
ON CONFLICT (name) DO UPDATE SET
  vendor        = COALESCE(NULLIF(EXCLUDED.vendor, ''),        public.products.vendor),
  category      = COALESCE(NULLIF(EXCLUDED.category, ''),      public.products.category),
  purchase_unit = COALESCE(NULLIF(EXCLUDED.purchase_unit, ''), public.products.purchase_unit);